-// isValidBase36 checks if a string contains only base36 characters
-func isValidBase36(s string) bool {
-	for _, c := range s {
-		if !((c >= '0' && c <= '9') || (c >= 'a' && c <= 'z')) {
-			return false
-		}
-	}
-	return true
-}
