-func validateIssueIDPrefix(id, prefix string) error {
-	expectedPrefix := prefix + "-"
-	if !strings.HasPrefix(id, expectedPrefix) {
-		return fmt.Errorf("issue ID '%s' does not match configured prefix '%s'", id, prefix)
-	}
